import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { Subject } from 'rxjs';
import { permissionsLabels } from 'src/app/shared/models/fmosNewRolePermissions';
import { ChargeMaintenanceService } from 'src/app/shared/services/charge-maintenance-service.service';
import { MaintenanceService } from 'src/app/shared/services/maintenance.service';
import { RoleService } from 'src/app/shared/services/role.service';
import Swal from 'sweetalert2';

@Component({
  selector: 'npr-department-id-maintenance',
  templateUrl: './department-id-maintenance.component.html',
  styleUrls: ['./department-id-maintenance.component.scss'],
})
export class DepartmentIdMaintenanceComponent implements OnInit {
  respArray: any[] = [];
  dtOptions: DataTables.Settings = {};
  dtTrigger: Subject<any> = new Subject<any>();
  isLoading: boolean = false;
  roleCodes = new permissionsLabels();
  statusArr: String[] = ['Authorized', 'Unauthorized', 'Open', 'Close'];
  respData: any;
  departmentService: any;
  currentUser: any;

  constructor(
    private apiService: MaintenanceService,
    private router: Router,
    private roleService: RoleService
  ) {}

  ngOnInit(): void {
    this.dtOptions = {
      pagingType: 'full_numbers',
      pageLength: 5,
      // columnDefs: [ { type: 'date', 'targets': ['inputTime'] } ],
      // order: [[4, 'desc']],
      processing: true,
      lengthMenu: [
        [5, 10, 20, 30,-1],
        [5, 10, 20, 30,"ALL"],
      ],
      columnDefs: [{ type: 'date', targets: [5] }],
      order: [[5, 'desc']],
    };
    this.getChargeMaintainenceSummary();
    this.roleService.fetchScreenPermissions('Department ID Maintenance');
    this.roleService.screenLabelList.subscribe(
      (message) => (this.roleCodes = message)
    );
    console.log(this.roleCodes);
  }

  getChargeMaintainenceSummary() {
    this.isLoading = true;
    this.apiService
      .gettingDepartmentDataInSummary()
      .subscribe((dataresp: any) => {
        for (let item of dataresp.result) {
          item.verifiedStatus = this.statusArr.find((i) =>
            i.startsWith(item.verifiedStatus)
          );
          item.recordStatus = this.statusArr.find((i)=>
          i.startsWith(item.recordStatus)
          );
        }
        this.respArray = dataresp.result;
        this.isLoading = false;

        this.dtTrigger.next();
      });
  }
  ngOnDestroy(): void {
    this.dtTrigger.unsubscribe();
  }
  new() {
    localStorage.removeItem('idValue');
    this.apiService.setIndex({
      index: '',
    });
    this.router.navigateByUrl(
      '/system-param-maintenance/dept-id-maintenance-new'
    );
  }
  edit(data) {
    this.apiService.setIndex({
      index: data.departId,
    });
    localStorage.setItem('idValue', data.departId);
    this.router.navigateByUrl(
      '/system-param-maintenance/dept-id-maintenance-new'
    );
  }
  auth(data) {
    Swal.fire({
      //text: 'Unable to process' + 'Error ' + this.responseforfileupload.errorMessage + 'Do you want to Proceed??',
      text: 'You are trying to Authorize record. ' + ' Do you want to proceed?',
      showCancelButton: true,
      confirmButtonColor: '#3e54b8',
      cancelButtonColor: '#d33',
      // confirmButtonText: 'PROCEED.'
      cancelButtonText: 'NO',
      confirmButtonText: 'YES',
      icon: 'info',
      iconColor: '#d33',
    }).then((result) => {
      console.log('this is reopen ', result);
      if (result.isConfirmed === true) {
        if (data.createdBy === localStorage.getItem('userFromLogin')) {
          Swal.fire({ text: 'Maker Cannot Authorize Record!', icon: 'error' });
          return;
        }
        console.log('this is authorzation');
        data.loggedInUser = this.currentUser;
        this.departmentService
          .onAuthDepartment('authorize', data).subscribe(
          (resp) => {
            console.log(resp);
            this.respData = resp;
            this.auditlog();
            if (resp) {
              Swal.fire({
                text: 'Record is Authorized',
                icon: 'success',
              }).then(() => window.location.reload());
            }
          }
          // (error) => {
          //   Swal.fire({ text: error.error.message, icon: 'error' });
          // }
        );
      }
    });
  }
  close(data) {
    Swal.fire({
      //text: 'Unable to process' + 'Error ' + this.responseforfileupload.errorMessage + 'Do you want to Proceed??',
      text: 'You are trying to Close record. ' + ' Do you want to proceed?',
      showCancelButton: true,
      confirmButtonColor: '#3e54b8',
      cancelButtonColor: '#d33',
      // confirmButtonText: 'PROCEED.'
      cancelButtonText: 'NO',
      confirmButtonText: 'YES',
      icon: 'info',
      iconColor: '#d33',
    }).then((result) => {
      console.log('this is reopen ', result);
      if (result.isConfirmed === true) {
        console.log('this is close');
        this.departmentService
        .onCloseOfDepartment('close', data).subscribe(
          (resp) => {
            console.log(resp);
            this.respData = resp;
            this.auditlog();
            if (this.respData) {
              Swal.fire({ text: 'Record is Closed' }).then(() =>
                window.location.reload()
              );
            }
          },
          (error) => {
            Swal.fire(error.error.message);
          }
        );
      }
    });
  }

  reopen(data) {
    Swal.fire({
      //text: 'Unable to process' + 'Error ' + this.responseforfileupload.errorMessage + 'Do you want to Proceed??',
      text: 'You are trying to Reopen record. ' + ' Do you want to proceed?',
      showCancelButton: true,
      confirmButtonColor: '#3e54b8',
      cancelButtonColor: '#d33',
      // confirmButtonText: 'PROCEED.'
      cancelButtonText: 'NO',
      confirmButtonText: 'YES',
      icon: 'info',
      iconColor: '#d33',
    }).then((result) => {
      console.log('this is reopen ', result);
      if (result.isConfirmed === true) {
        this.departmentService
        .onReopenOfDepartment('reopen', data).subscribe(
          (resp) => {
            console.log(resp);
            this.respData = resp;
            this.auditlog();
            if (this.respData) {
              this.auditlog();
              Swal.fire({
                text: 'Record is Reopened',
              }).then(() => window.location.reload());
            } else {
              Swal.fire({ text: 'Record cannot be opened ' });
            }
          },
          (error) => {
            Swal.fire(error.error.message);
          }
        );
      }
    });
  }
  auditlog() {
    if (this.respData.recordStatus == 'O') {
      this.respData.recordStatus = 'OPEN';
    } else if (this.respData.recordStatus == 'C') {
      this.respData.recordStatus = 'CLOSE';
    }
    if (
      this.respData.authStatus == 'A' ||
      this.respData.authStatus == 'Authorized'
    ) {
      this.respData.authStatus = 'AUTHORIZED';
    } else if (
      this.respData.authStatus == 'U' ||
      this.respData.authStatus == 'Unauthorized'
    ) {
      this.respData.authStatus = 'UNAUTHORIZED';
    }
    if (this.respData.firstTimeAuth == 'Y') {
      this.respData.firstTimeAuth = 'YES';
    } else if (this.respData.firstTimeAuth == 'N') {
      this.respData.firstTimeAuth = 'NO';
    }
  }
}
